#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &arr[i]);
        // frequency using hash table (simple array because Ai <= 1e6)
        static int freq[1000001];
        // reset only used entries
        int maxVal=0;
        for(int i=0;i<N;i++){
            int v=arr[i];
            freq[v]++;
            if(v>maxVal) maxVal=v;
        }
        long long total = (long long)N*(N-1);
        long long equalPairs=0;
        for(int v=1; v<=maxVal; ++v){
            if(freq[v]>1){
                long long f = freq[v];
                equalPairs += f*(f-1);
                freq[v]=0; // reset for next test case
            }
        }
        // also reset any freq that were 1 (to 0)
        for(int i=0;i<N;i++) freq[arr[i]]=0;
        printf("%lld\n", total - equalPairs);
        free(arr);
    }
    return 0;
}

