#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        freq = {}
        for _ in range(n):
            v = int(next(it))
            freq[v] = freq.get(v, 0) + 1
        total = n * (n - 1)
        equal = sum(f * (f - 1) for f in freq.values())
        out_lines.append(str(total - equal))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

